import { describe, expect, it } from "vitest"
import {
  compileDesign,
  connector,
  harness,
  runRules,
  wire,
  type ConnectorPart
} from "@grayhaven/nerve"
import { MolexMicroFit } from "@grayhaven/nerve-connectors"
import {
  builtinRules,
  missingSeal,
  requireApprovedParts,
  sealIncompatible,
  terminalIncompatible
} from "@grayhaven/nerve-rules"

const sealedPart: ConnectorPart = {
  mpn: "SEALED-2",
  pinCount: 2,
  sealed: true,
  compatibleTerminals: ["T-100"],
  compatibleSeals: ["S-100"]
}

const make = (
  opts: Parameters<typeof connector>[2],
  partOverride: Partial<ConnectorPart> = {}
) => {
  const part = { ...sealedPart, ...partOverride }
  const a = connector("J1", part, opts)
  const b = connector("J2", part, opts)
  return compileDesign(
    harness("registry-fixture", {
      revision: "A",
      units: "mm",
      connectors: [a, b],
      wires: [
        wire("W1", a.pin(1), b.pin(1), { gauge: "20AWG", color: "red", length: 100, signal: "SIG" }),
        wire("W2", a.pin(2), b.pin(2), { gauge: "20AWG", color: "black", length: 100, signal: "GND" })
      ]
    })
  ).hir
}

describe("per-pin terminals and seals (PRD §30)", () => {
  it("carries terminal/seal assignments into HIR pins and the BOM", () => {
    const hir = make({
      pins: { 1: "SIG", 2: "GND" },
      terminals: "T-100",
      seals: { 1: "S-100", 2: "S-100" }
    })
    expect(hir.connectors[0]?.pins[0]).toMatchObject({
      pin: "1",
      terminal: "T-100",
      seal: "S-100"
    })
    const bom = Object.fromEntries(hir.bom.map((i) => [i.mpn, i]))
    expect(bom["T-100"]).toMatchObject({ category: "terminal", quantity: 4 })
    expect(bom["S-100"]).toMatchObject({ category: "seal", quantity: 4 })
    expect(bom["T-100"]?.usedBy).toContain("connector:J1.pin:1")
  })

  it("HK-CONN-012: terminal not in the part's compatible list", () => {
    const hir = make({ pins: { 1: "SIG", 2: "GND" }, terminals: "WRONG-1", seals: "S-100" })
    const diags = runRules(hir, [terminalIncompatible])
    expect(diags.map((d) => d.code)).toEqual(["HK-CONN-012", "HK-CONN-012", "HK-CONN-012", "HK-CONN-012"])
    expect(diags[0]?.message).toContain("allowed: T-100")
  })

  it("HK-CONN-013: sealed connector with unsealed populated pin", () => {
    const hir = make({ pins: { 1: "SIG", 2: "GND" }, terminals: "T-100" })
    const diags = runRules(hir, [missingSeal])
    expect(diags).toHaveLength(4) // 2 pins × 2 connectors
    expect(diags[0]?.code).toBe("HK-CONN-013")
  })

  it("HK-CONN-014: seal not in the part's compatible list", () => {
    const hir = make({ pins: { 1: "SIG", 2: "GND" }, terminals: "T-100", seals: "WRONG-S" })
    const diags = runRules(hir, [sealIncompatible])
    expect(diags[0]?.code).toBe("HK-CONN-014")
  })

  it("a fully sealed, compatible assignment passes all built-ins", () => {
    const hir = make({ pins: { 1: "SIG", 2: "GND" }, terminals: "T-100", seals: "S-100" })
    expect(
      runRules(hir, builtinRules).filter((d) => d.severity === "error")
    ).toEqual([])
  })
})

describe("approvals and provenance (PRD §30 acceptance)", () => {
  it("requireApprovedParts flags BOM items off the org list without mutating library data", () => {
    const hir = make({ pins: { 1: "SIG", 2: "GND" }, terminals: "T-100", seals: "S-100" })
    const diags = runRules(hir, [requireApprovedParts(["SEALED-2", "T-100"])])
    expect(diags.map((d) => d.target)).toEqual(["bom:S-100"])
    expect(diags[0]?.code).toBe("HK-DOC-004")
    // Library part object is untouched — approval lives in org config.
    expect("approved" in sealedPart).toBe(false)
  })

  it("library parts carry provenance into HIR", () => {
    const j1 = connector("J1", MolexMicroFit["43025-0800"], { pins: { 1: "SIG" } })
    const j2 = connector("J2", MolexMicroFit["43020-0800"], { pins: { 1: "SIG" } })
    const { hir } = compileDesign(
      harness("prov", {
        revision: "A",
        units: "mm",
        connectors: [j1, j2],
        wires: [wire("W1", j1.pin(1), j2.pin(1), { gauge: "20AWG", color: "red", length: 50, signal: "SIG" })]
      })
    )
    expect(hir.connectors[0]?.provenance).toMatchObject({ verification: "verified", lastVerified: "2026-06-06" })
    expect(hir.connectors[0]?.crimpTool).toBe("63819-0000")
  })
})

test/code-numbers.test.ts.source:
import { describe, expect, it } from "vitest"
import {
  builtinRules,
  codesToNumbers,
  ruleCategory,
  ruleCodeFromNumber,
  ruleCodeNumber
} from "@grayhaven/nerve-rules"

describe("rule code numbers", () => {
  it("round-trips every built-in rule code", () => {
    for (const r of builtinRules) {
      const n = ruleCodeNumber(r.code)
      expect(n, r.code).toBeDefined()
      expect(ruleCodeFromNumber(n!), r.code).toBe(r.code)
    }
  })

  it("built-in numbers are unique and sort by category band", () => {
    const ns = builtinRules.map((r) => ruleCodeNumber(r.code)!)
    expect(new Set(ns).size).toBe(ns.length)
    expect(ruleCodeNumber("HK-DOC-001")).toBe(1001)
    expect(ruleCodeNumber("HK-MFG-004")).toBe(2004)
    expect(ruleCodeNumber("HK-WIRE-004")).toBe(3004)
    expect(ruleCodeNumber("HK-ELEC-003")).toBe(4003)
    expect(ruleCodeNumber("HK-CONN-011")).toBe(5011)
  })

  it("custom and malformed codes return undefined (strings stay the contract)", () => {
    for (const code of ["ORG-042", "SHOP-001", "HK-NOPE-001", "HK-DOC-1", "HK-DOC-0001", ""]) {
      expect(ruleCodeNumber(code), code).toBeUndefined()
    }
    expect(ruleCodeFromNumber(6001)).toBeUndefined() // no band
    expect(ruleCodeFromNumber(1000)).toBeUndefined() // suffix 0 invalid
    expect(ruleCodeFromNumber(2004.5)).toBeUndefined()
  })

  it("category math works from either representation", () => {
    expect(ruleCategory("HK-ELEC-001")).toBe("ELEC")
    expect(ruleCategory(5011)).toBe("CONN")
    expect(ruleCategory("ORG-042")).toBeUndefined()
  })

  it("codesToNumbers dedupes, sorts, and drops custom codes", () => {
    expect(codesToNumbers(["HK-CONN-011", "HK-DOC-001", "HK-CONN-011", "ORG-042"])).toEqual([
      1001, 5011
    ])
  })
})

test/mutation-survivors.test.ts.source:
/**
 * Mutation-audit killers: each test here exists because a Stryker mutant
 * SURVIVED the suite (2026-06-07 audit, score 85.84%). Mostly negative
 * assertions — the suite proved what fires, but not what must NOT match,
 * so anchor-dropping regex mutants lived.
 */
import { describe, expect, it } from "vitest"
import {
  differentialPartner,
  isPowerSignal,
  parseAwg,
  ruleCodeFromNumber,
  ruleCodeNumber
} from "@grayhaven/nerve-rules"

describe("differentialPartner anchors (regex mutants)", () => {
  it("does not pair signals with trailing garbage (kills $-drop mutants)", () => {
    expect(differentialPartner("CAN_H_SHIELD")).toBeUndefined()
    expect(differentialPartner("RS485_A_TAP")).toBeUndefined()
    expect(differentialPartner("USB_DP_OLD")).toBeUndefined()
    expect(differentialPartner("SIG_P_X")).toBeUndefined()
  })

  it("pairs the no-underscore spellings (kills _?-tightening mutants)", () => {
    expect(differentialPartner("CANH")).toBe("CANL")
    expect(differentialPartner("CANL")).toBe("CANH")
    expect(differentialPartner("RS485A")).toBe("RS485B")
    expect(differentialPartner("USBDP")).toBe("USBDM")
    expect(differentialPartner("USBDM")).toBe("USBDP")
  })

  it("bus index must be digits (kills \\d->\\D mutant)", () => {
    expect(differentialPartner("CANX_L")).toBeUndefined()
    expect(differentialPartner("CAN12_H")).toBe("CAN12_L")
  })
})

describe("signal classification edges", () => {
  it("decimal voltage rails are power (kills \\d+->\\d in POWER_SIGNAL)", () => {
    expect(isPowerSignal("3.3V")).toBe(true)
    expect(isPowerSignal("3.25V_RAIL")).toBe(true)
    expect(isPowerSignal("+1.85V")).toBe(true)
  })
})

describe("parseAwg edges", () => {
  it("rejects zero and keeps whitespace tolerance", () => {
    expect(parseAwg("0AWG")).toBeUndefined()
    expect(parseAwg("  18 AWG  ")).toBe(18)
  })
})

describe("rule-code numeric boundaries", () => {
  it("suffix 999 stays in band; 1000 is impossible by grammar", () => {
    expect(ruleCodeNumber("HK-DOC-999")).toBe(1999)
    expect(ruleCodeFromNumber(1999)).toBe("HK-DOC-999")
    expect(ruleCodeNumber("HK-DOC-1000")).toBeUndefined()
  })
})
